return $input.all().map(item => {
  const isoTime = item.json.time;

  const date = new Date(isoTime).toLocaleString('en-US', {
    timeZone: 'Asia/Kolkata',  // 🔁 Change this to your UAT timezone
    year: 'numeric',
    month: 'long',
    day: 'numeric',
    hour: 'numeric',
    minute: '2-digit',
    hour12: true
  });

  return {
    json: {
      ...item.json,
      time: date
    }
  };
});
